/* ----------------------------- ROUTER ----------------------------- */
const PAGES = ["home", "about", "services", "artists", "presskit", "contact"];
function parseHash() {
  const h = (window.location.hash || "").replace(/^#\/?/, "").trim();
  if (!h) return "home";
  const parts = h.split("/");
  if (parts[0] === "artist" && PROFILES[parts[1]]) return "artist:" + parts[1];
  return PAGES.includes(parts[0]) ? parts[0] : "home";
}
function go(route) { window.location.hash = route.startsWith("artist:") ? `#/artist/${route.split(":")[1]}` : `#/${route}`; }

/* ----------------------------- ATOMS ----------------------------- */
function Reveal({ children, delay = 0, as: Tag = "div", className = "" }) {
  const ref = useRef(null); const [seen, setSeen] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setSeen(true); io.disconnect(); } }, { threshold: 0.12 });
    io.observe(el); return () => io.disconnect();
  }, []);
  return <Tag ref={ref} className={`reveal ${seen ? "in" : ""} ${className}`} style={{ transitionDelay: `${delay}ms` }}>{children}</Tag>;
}

function VinylMark({ size = 18 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" className="vmark" aria-hidden="true">
      <circle cx="12" cy="12" r="11" fill="none" stroke="currentColor" strokeWidth="1" opacity=".5" />
      <circle cx="12" cy="12" r="7.5" fill="none" stroke="currentColor" strokeWidth="1" opacity=".35" />
      <path d="M12 6c-1.6 2-3 3.4-3 5.4A3 3 0 0 0 15 11.4C15 9.4 13.6 8 12 6z" fill="currentColor" />
    </svg>
  );
}

function Eyebrow({ n, children }) {
  return <span className="eyebrow">{n && <em>{n}</em>}{children}</span>;
}

function Ticker() {
  const row = [...MARQUEE, ...MARQUEE];
  return (
    <div className="ticker" aria-hidden="true">
      <div className="ticker__in">
        {row.map((t, i) => <span className="ticker__it" key={i}><i>★</i>{t}</span>)}
      </div>
    </div>
  );
}

function Media({ slot, mono = "DF", alt = "", ratio = "4 / 5", className = "" }) {
  const src = slot && IMAGES[slot];
  return (
    <div className={`media ${className}`} style={{ aspectRatio: ratio }}>
      {src ? <img src={src} alt={alt} loading="lazy" />
        : <div className="media__ph"><VinylMark size={40} /><span>{mono}</span><i>photo</i></div>}
    </div>
  );
}

function Btn({ kind = "primary", children, onClick, href, lg, block, ...rest }) {
  const cls = `btn btn--${kind} ${lg ? "btn--lg" : ""} ${block ? "btn--block" : ""}`;
  if (href) return <a className={cls} href={href} {...rest}>{children}</a>;
  return <button className={cls} onClick={onClick} {...rest}>{children}</button>;
}

/* ----------------------------- NAV / FOOTER ----------------------------- */
function Nav({ route }) {
  const [open, setOpen] = useState(false);
  const links = [["home", "Home"], ["about", "About"], ["services", "Services"], ["artists", "Artists"], ["presskit", "Press Kit"], ["contact", "Contact"]];
  const nav = (r) => { go(r); setOpen(false); };
  const active = (r) => route === r || (r === "artists" && route.startsWith("artist:"));
  return (
    <header className="nav">
      <div className="nav__bar">
        <button className="logo" onClick={() => nav("home")}><VinylMark size={20} /> D'<span>FLAMZ</span></button>
        <nav className="nav__links">
          {links.map(([r, l]) => <button key={r} className={`nav__a ${active(r) ? "on" : ""}`} onClick={() => nav(r)}>{l}</button>)}
        </nav>
        <button className="nav__cta" onClick={() => nav("contact")}>Book a DJ</button>
        <button className="nav__burger" onClick={() => setOpen(o => !o)} aria-label="Menu">{open ? "✕" : "☰"}</button>
      </div>
      {open && (
        <div className="nav__m">
          {links.map(([r, l]) => <button key={r} className={`nav__ma ${active(r) ? "on" : ""}`} onClick={() => nav(r)}>{l}</button>)}
          <button className="btn btn--primary btn--block" onClick={() => nav("contact")}>Book a DJ</button>
        </div>
      )}
    </header>
  );
}

